import sys
import heapq
class Solution:
    def maxPoints(self, cards: list[list[int]]) -> int:
        max_heap = []
        for student_cards in cards:
            total_points = sum(student_cards)
            heapq.heappush(max_heap, -total_points)
        lo, hi = 0, -max_heap[0]
        while lo < hi:
            mid = (lo + hi) // 2
            temp_heap = []
            for student_cards in cards:
                points = 0
                student_cards.sort()
                for card in student_cards:
                    if points + card <= mid:
                        points += card
                    else:
                        break
                heapq.heappush(temp_heap, -points)
            if -temp_heap[0] <= mid:
                hi = mid
            else:
                lo = mid + 1
        return lo
