#include <numeric>
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int maxPoints(vector<vector<int>>& cards) {
        priority_queue<long long, vector<long long>, greater<long long>> min_heap;
        for (auto& student_cards : cards) {
            long long total_points = 0;
            for (int points : student_cards) {
                total_points += points;
            }
            min_heap.push(total_points);
        }
        long long lo = 0, hi = min_heap.top();
        while (lo < hi) {
            long long mid = lo + (hi - lo) / 2;
            priority_queue<long long, vector<long long>, greater<long long>> temp_heap;
            for (auto& student_cards : cards) {
                long long points = 0;
                sort(student_cards.begin(), student_cards.end());
                for (int card : student_cards) {
                    if (points + card <= mid) {
                        points += card;
                    } else {
                        break;
                    }
                }
                temp_heap.push(points);
            }
            if (temp_heap.top() <= mid) {
                hi = mid;
            } else {
                lo = mid + 1;
            }
        }
        return lo;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, m;
    cin >> n >> m;
    vector<vector<int>> cards(n, vector<int>(m));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cin >> cards[i][j];
        }
    }
    Solution sol;
    int ans = sol.maxPoints(cards);
    cout << ans << '\n';
    return 0;
}
